ll k[5][MAXN],ma[5][MAXN];



int main()

{

	scanf("%d%lld",&n,&c);

	for(register int i=1;i<=n;i++)

		scanf("%lld%lld",&x[i],&v[i]);

	x[n+1]=c;  x[0]=0LL;

	long long sum=0LL,ans=-1e18;

	for(register int i=1;i<=n;i++)

	{

		sum=sum-(x[i]-x[i-1])+v[i];

		ans=max(ans,sum);

	}

	sum=0LL;

	for(register int i=n;i>=1;i--)

	{

		sum=sum-(x[i+1]-x[i])+v[i];

		ans=max(ans,sum);

	}

